        class MultiTapeTM:
            def __init__(self):
                self.transitions = {
                    ('q0', ('a', '_')): ('q1', ('b', 'a'), ('R', 'R')),
                    ('q0', ('b', '_')): ('q1', ('a', 'b'), ('R', 'R')),
                    ('q1', ('a', '_')): ('q2', ('a', 'a'), ('R', 'R')),
                    ('q1', ('b', '_')): ('q2', ('b', 'b'), ('R', 'R')),
                    ('q2', ('_', '_')): ('qaccept', ('_', '_'), ('S', 'S'))
                }

            def simulate(self, input1, input2=""):
                # Initialize tapes
                tape1 = list(input1) + ['_'] * 10
                tape2 = list(input2) + ['_'] * 10 if input2 else ['_'] * 10
                head1, head2 = 0, 0
                current_state = 'q0'
                step_count = 0
                write_count = 0

                while current_state != 'qaccept':
                    # Extend tapes if needed
                    while head1 >= len(tape1):
                        tape1.extend(['_'] * 5)
                    while head2 >= len(tape2):
                        tape2.extend(['_'] * 5)

                    symbols = (tape1[head1], tape2[head2])

                    if (current_state, symbols) not in self.transitions:
                        break  # No transition available

                    next_state, write_symbols, directions = self.transitions[(current_state, symbols)]

                    # Write symbols
                    if tape1[head1] != write_symbols[0]:
                        write_count += 1
                    if tape2[head2] != write_symbols[1]:
                        write_count += 1

                    tape1[head1] = write_symbols[0]
                    tape2[head2] = write_symbols[1]

                    # Move heads
                    if directions[0] == 'R':
                        head1 += 1
                    elif directions[0] == 'L':
                        head1 = max(0, head1 - 1)

                    if directions[1] == 'R':
                        head2 += 1
                    elif directions[1] == 'L':
                        head2 = max(0, head2 - 1)

                    current_state = next_state
                    step_count += 1

                    if step_count > 50:  # Safety limit
                        break

                # Clean up tapes for comparison
                def clean_tape(tape):
                    result = []
                    for i, symbol in enumerate(tape):
                        result.append(symbol)
                        if i >= 2 and symbol == '_':  # Keep at least one blank
                            break
                    return ''.join(result)

                return step_count, clean_tape(tape1), clean_tape(tape2), write_count

