def verify_answer(answer):
    try:
        steps, final_state, final_tape2_str, max_syms = answer

        class TwoTapeTM:
            def __init__(self, input_str):
                self.tape1 = list(input_str)
                self.tape2 = ['B'] * 20 # Pre-allocate tape 2
                self.head1 = 0
                self.head2 = 0
                self.state = 'q_equal'
                self.step_count = 0
                self.max_tape2_len = 0

            def run(self):
                # This is a simplified, high-level simulation where each input symbol process is one "step"
                # This matches the state-based logic rather than low-level head movements.
                while self.state not in ['q_accept', 'q_reject'] and self.head1 <= len(self.tape1):
                    current_len = len(''.join(self.tape2).strip('B'))
                    if current_len > self.max_tape2_len:
                        self.max_tape2_len = current_len

                    t1_symbol = self.tape1[self.head1] if self.head1 < len(self.tape1) else 'B'

                    if self.state == 'q_equal':
                        if t1_symbol == '0':
                            self.state = 'q_excess_zero'
                            self.tape2[self.head2] = 'Z'
                            self.head2 += 1
                        elif t1_symbol == '1':
                            self.state = 'q_excess_one'
                            self.tape2[self.head2] = 'O'
                            self.head2 += 1
                        elif t1_symbol == 'B':
                            self.state = 'q_accept'

                    elif self.state == 'q_excess_zero':
                        if t1_symbol == '0':
                            self.tape2[self.head2] = 'Z'
                            self.head2 += 1
                        elif t1_symbol == '1':
                            self.head2 -= 1
                            self.tape2[self.head2] = 'B'
                            if self.head2 == 0:
                                self.state = 'q_equal'
                        elif t1_symbol == 'B':
                            self.state = 'q_reject'

                    elif self.state == 'q_excess_one':
                        if t1_symbol == '1':
                            self.tape2[self.head2] = 'O'
                            self.head2 += 1
                        elif t1_symbol == '0':
                            self.head2 -= 1
                            self.tape2[self.head2] = 'B'
                            if self.head2 == 0:
                                self.state = 'q_equal'
                        elif t1_symbol == 'B':
                            self.state = 'q_reject'

                    self.head1 += 1
                    self.step_count += 1

                final_tape_content = ''.join(self.tape2).strip('B')
                if not final_tape_content:
                    final_tape_content = 'B'

                return self.step_count, self.state, final_tape_content, self.max_tape2_len

        tm = TwoTapeTM("1010")
