def verify_answer(answer):
    try:
        # Deconstruct the answer tuple
        steps, state, max_pos, x_writes = answer

        class SimulateLBA:
            def __init__(self, input_str):
                # Construct the tape: $ + input + #
                self.tape = ['$', *list(input_str), '#']
                self.head = 0
                self.n = input_str.count('a')
                self.steps = 0
                self.max_pos = 0
                self.x_writes = 0

            def move(self, direction):
                if direction == 'R':
                    self.head += 1
                elif direction == 'L':
                    self.head -= 1
                self.steps += 1
                self.max_pos = max(self.max_pos, self.head)

            def write(self, sym):
                old = self.tape[self.head]
                self.tape[self.head] = sym
                if sym == 'X' and old == 'a':
                    self.x_writes += 1

            def run(self):
                # Execute the original algorithm logic
                # Phase 1: Initial scan to find '#'
                self.head = 1
                while self.tape[self.head] != '#':
                    self.move('R')

                # Phase 2: Start trial division
                for d in range(2, self.n):
                    # Reset head to the first 'a' after '$'
                    while self.tape[self.head] != '$':
                        self.move('L')
                    self.move('R')

                    # Mark every d-th 'a' as 'X'
                    count = 0
                    while self.head < len(self.tape) - 1:
                        if self.tape[self.head] == 'a':
                            count += 1
                            if count % d == 0:
                                self.write('X')
                        self.move('R')

                    # Check if input is divisible by d
                    if self.n % d == 0:
                        return self.steps, 'q_reject', self.max_pos, self.x_writes

                    # Restore: Change 'X' back to 'a'
                    while self.tape[self.head] != '$':
                        if self.tape[self.head] == 'X':
                            self.tape[self.head] = 'a'
                        self.move('L')
                    self.move('R')

                return self.steps, 'q_accept', self.max_pos, self.x_writes

        # Initialize and run simulator with test input
        simulator = SimulateLBA('aaaaaaa')
        computed_steps, computed_state, computed_max_pos, computed_x_writes = simulator.run()

        # Comparison for verification
        return (
            computed_steps == steps and
            computed_state == state and
            computed_max_pos == max_pos and
            computed_x_writes == x_writes
        )

    except Exception:
        return None

