        class WW_LBA:
            def __init__(self):
                # Build complete transition function
                # Key: (state, symbol, position_context), Value: (new_state, write_symbol, direction)
                self.transitions = {}

                # Basic transitions from problem description
                self.basic_transitions = {
                    ('q0', 'a'): ('q1', 'X', 'R'),
                    ('q0', 'b'): ('q2', 'Y', 'R'),
                    ('q0', '#'): ('q4', '#', 'S'),  # Check acceptance condition
                    ('q1', 'a'): ('q1', 'a', 'R'),  # First half
                    ('q1', 'b'): ('q1', 'b', 'R'),  # First half
                    ('q1', '#'): ('q1', '#', 'R'),
                    ('q2', 'a'): ('q2', 'a', 'R'),  # First half
                    ('q2', 'b'): ('q2', 'b', 'R'),  # First half
                    ('q2', '#'): ('q2', '#', 'R'),
                    ('q3', 'a'): ('q3', 'a', 'L'),
                    ('q3', 'b'): ('q3', 'b', 'L'),
                    ('q3', '#'): ('q3', '#', 'L'),
                    ('q3', 'X'): ('q0', 'X', 'R'),
                    ('q3', 'Y'): ('q0', 'Y', 'R'),
                    ('q3', 'Z'): ('q3', 'Z', 'L'),
                    ('q3', 'W'): ('q3', 'W', 'L'),
                    # State q4: Check if all symbols are properly marked
                    ('q4', 'X'): ('q4', 'X', 'R'),
                    ('q4', 'Y'): ('q4', 'Y', 'R'),
                    ('q4', '#'): ('q4', '#', 'R'),
                    ('q4', 'Z'): ('q4', 'Z', 'R'),
                    ('q4', 'W'): ('q4', 'W', 'R'),
                }

            def get_transition(self, state, symbol, head_pos, tape):
                """Get transition based on state, symbol, and context"""

                # Find middle position
                try:
                    middle_pos = tape.index('#')
                except ValueError:
                    return None

                # Context-sensitive transitions
                if state == 'q1' and symbol == 'a' and head_pos > middle_pos:
                    # Mark matching 'a' in second half
                    return ('q3', 'Z', 'L')
                elif state == 'q2' and symbol == 'b' and head_pos > middle_pos:
                    # Mark matching 'b' in second half
                    return ('q3', 'W', 'L')
                elif state == 'q4' and head_pos >= len(tape):
                    # Reached end in checking state - accept if all properly marked
                    return ('qaccept', None, 'S')
                elif state == 'q1' and symbol in ['Z', 'W'] and head_pos > middle_pos:
                    # Mismatch - reject
                    return ('qreject', symbol, 'S')
                elif state == 'q2' and symbol in ['Z', 'W'] and head_pos > middle_pos:
                    # Mismatch - reject  
                    return ('qreject', symbol, 'S')
                elif state == 'q1' and symbol == 'b' and head_pos > middle_pos:
                    # Looking for 'a' but found 'b' in second half - reject
                    return ('qreject', symbol, 'S')
                elif state == 'q2' and symbol == 'a' and head_pos > middle_pos:
                    # Looking for 'b' but found 'a' in second half - reject
                    return ('qreject', symbol, 'S')

                # Use basic transitions
                if (state, symbol) in self.basic_transitions:
                    return self.basic_transitions[(state, symbol)]

                # No valid transition - reject
                return ('qreject', symbol, 'S')

            def simulate(self, input_string):
                tape = list(input_string)
                head_pos = 0
                current_state = 'q0'
                step_count = 0
                x_y_marks = 0  # Count X and Y marks
                z_w_marks = 0  # Count Z and W marks

                while current_state not in ['qaccept', 'qreject'] and step_count < 100:
                    if head_pos >= len(tape):
                        if current_state == 'q4':
                            # In checking state and reached end - accept
                            current_state = 'qaccept'
                        else:
                            current_state = 'qreject'
                        break

                    if head_pos < 0:
                        current_state = 'qreject'
                        break

                    current_symbol = tape[head_pos]
                    transition = self.get_transition(current_state, current_symbol, head_pos, tape)

                    if transition is None:
                        current_state = 'qreject'
                        break

                    next_state, write_symbol, direction = transition

                    # Count new marks
                    if write_symbol and tape[head_pos] != write_symbol:
                        if write_symbol in ['X', 'Y']:
                            x_y_marks += 1
                        elif write_symbol in ['Z', 'W']:
                            z_w_marks += 1

                    # Apply transition
                    if write_symbol:
                        tape[head_pos] = write_symbol

                    if direction == 'R':
                        head_pos += 1
                    elif direction == 'L':
                        head_pos -= 1
                    # direction 'S' means stay

                    current_state = next_state
                    step_count += 1

                return step_count, current_state, x_y_marks, z_w_marks

        lba = WW_LBA()
