                }

            def get_transition(self, state, symbol, head_pos, tape, direction_history):
                """Get transition based on state, symbol, and context"""

                # Context-sensitive logic
                if state == 'q1':
                    if symbol == 'a':
                        # Check if we're scanning right (haven't turned around yet)
                        if head_pos < len(tape) - 1 and tape[head_pos + 1] != '$':
