def verify_answer(answer):
    try:
        derivation_steps, cs_rules_used, max_length, length_violations = answer

        from collections import deque

        class LengthConstrainedCSG:
            def __init__(self, max_len=12, max_steps=40):
                self.max_len = max_len
                self.max_steps = max_steps

            def apply_rules(self, s):
                next_states = []  # (next_form, is_context_sensitive)

                # Rule 1: S -> AB
                i = s.find('S')
                while i != -1:
                    next_states.append((s[:i] + 'AB' + s[i+1:], False))
                    i = s.find('S', i + 1)

                # Rule 2: A -> aAa | aa
                i = s.find('A')
                while i != -1:
                    next_states.append((s[:i] + 'aAa' + s[i+1:], False))
                    next_states.append((s[:i] + 'aa' + s[i+1:], False))
                    i = s.find('A', i + 1)

                # Rule 3: B -> bBb | bb
                i = s.find('B')
                while i != -1:
                    next_states.append((s[:i] + 'bBb' + s[i+1:], False))
                    next_states.append((s[:i] + 'bb' + s[i+1:], False))
                    i = s.find('B', i + 1)

                # Rule 4: AaB -> AXB (context-sensitive)
                start = 0
                while True:
                    j = s.find('AaB', start)
                    if j == -1:
                        break
                    next_states.append((s[:j] + 'AXB' + s[j+3:], True))
                    start = j + 1

                # Rule 5: XbB -> XYB (context-sensitive)
                start = 0
                while True:
                    j = s.find('XbB', start)
                    if j == -1:
                        break
                    next_states.append((s[:j] + 'XYB' + s[j+3:], True))
                    start = j + 1

                # Rule 6: XY -> xy (context-sensitive)
                start = 0
                while True:
                    j = s.find('XY', start)
                    if j == -1:
                        break
                    next_states.append((s[:j] + 'xy' + s[j+2:], True))
                    start = j + 1

                return next_states

            def derive_with_constraints(self, target='aaxybb'):
                # BFS to find a valid derivation with minimal steps under length constraint
                initial = ('S', 0, 1, 0)  # (form, cs_count, max_len_so_far, violations)
                q = deque([(initial, 0)])  # ((state_tuple), steps)
                visited = set(['S'])

                while q:
                    (form, cs_count, max_len_so_far, violations), steps = q.popleft()

                    if form == target:
                        return steps, cs_count, max_len_so_far, violations

                    if steps >= self.max_steps:
                        continue

                    for next_form, is_cs in self.apply_rules(form):
                        new_len = len(next_form)
                        # Enforce length constraint; do not explore over-limit nodes
                        if new_len > self.max_len:
                            continue
                        if next_form in visited:
                            continue
                        visited.add(next_form)
                        q.append(((next_form, cs_count + (1 if is_cs else 0), max(max_len_so_far, new_len), violations), steps + 1))

                # Not derivable within constraints
                return None

        csg = LengthConstrainedCSG()
        result = csg.derive_with_constraints('aaxybb')

        if result is None:
            # Use sentinel when no valid derivation exists within constraints
            return (derivation_steps, cs_rules_used, max_length, length_violations) == (-1, 0, 0, 0)
        else:
            return (derivation_steps, cs_rules_used, max_length, length_violations) == result
    except Exception:
        return False

