                    'S': [('A', 'B'), ('B', 'C')],
                    'A': [('B', 'A'), ('a',)],
                    'B': [('C', 'C'), ('b',)],
                    'C': [('A', 'B'), ('a',)]
                }
                self.terminals = {'a': ['A', 'C'], 'b': ['B']}

            def cyk_parse(self, string):
                n = len(string)
                if n == 0:
                    return 0, 0, False, 0

                # Initialize CYK table
                table = [[set() for _ in range(n)] for _ in range(n)]

                # Count of applied productions (terminals + binary)
                productions_count = 0

                # Fill diagonal (length 1 substrings) with terminal productions
                for i in range(n):
                    char = string[i]
                    if char in self.terminals:
                        for nonterminal in self.terminals[char]:
                            if nonterminal not in table[i][i]:
                                table[i][i].add(nonterminal)
                            # Applying a terminal production counts once per mapping
                            productions_count += 1

                # Fill table for longer substrings (binary productions)
                for length in range(2, n + 1):  # substring length
                    for i in range(n - length + 1):  # start position
                        j = i + length - 1  # end position

                        # Try all possible splits
                        for k in range(i, j):  # split position
                            left_set = table[i][k]
                            right_set = table[k + 1][j]

                            # Check all grammar rules
                            for nonterminal, productions in self.grammar.items():
                                for production in productions:
