                self.l2_transitions = {
                    'p0': {'0': ['p0', 'p1'], '1': ['p0']},
                    'p1': {'1': ['p2']},
                    'p2': {'0': ['p2'], '1': ['p2']}
                }
                self.l2_start = 'p0'
                self.l2_accept = {'p2'}

            def convert_nfa_to_dfa(self):
                """Convert NFA L2 to equivalent DFA using subset construction.
                Returns: (state_count, dfa_transitions, dfa_accept_set, dfa_state_names)
                dfa_transitions maps (state_name, symbol) -> state_name
                dfa_state_names is a set of state_name strings (e.g., {'D0','D1',...})
                """
                initial_set = frozenset([self.l2_start])
                dfa_states_map = {initial_set: 'D0'}
                work_list = [initial_set]
                next_id = 1
                dfa_transitions = {}

                alphabet = ['0', '1']

                while work_list:
                    current_set = work_list.pop(0)
                    current_name = dfa_states_map[current_set]

                    for symbol in alphabet:
                        next_set = set()
                        for state in current_set:
                            if state in self.l2_transitions and symbol in self.l2_transitions[state]:
                                next_set.update(self.l2_transitions[state][symbol])
                        next_frozen = frozenset(next_set)
                        if next_frozen and next_frozen not in dfa_states_map:
                            dfa_states_map[next_frozen] = f'D{next_id}'
                            work_list.append(next_frozen)
                            next_id += 1
                        if next_frozen:
                            dfa_transitions[(current_name, symbol)] = dfa_states_map[next_frozen]

                # Accepting DFA states: any subset containing an NFA accept state
                dfa_accept = set()
                for state_set, state_name in dfa_states_map.items():
                    if state_set & self.l2_accept:
                        dfa_accept.add(state_name)

                dfa_state_names = set(dfa_states_map.values())
                return len(dfa_state_names), dfa_transitions, dfa_accept, dfa_state_names

            def analyze_product_and_symdiff(self, l2_dfa_trans, l2_dfa_accept, l2_dfa_states):
                """Build product automaton L1 x L2_DFA and BFS over product graph.
                Returns: (total_product_states, reachable_symdiff_count, witness)
                """
                l1_states = set(self.l1_states)
                total_product_states = len(l1_states) * len(l2_dfa_states)

                start_pair = (self.l1_start, 'D0')
                from collections import deque
                queue = deque()
                queue.append((start_pair, ''))
                visited = set([start_pair])

                # Track reachable symmetric-difference pairs and first witness
                symdiff_visited = set()
                first_witness = None

                symbols = ['0', '1']
                while queue:
                    (q1_state, q2_state), w = queue.popleft()

                    # Check acceptance difference at current pair
                    l1_acc = q1_state in self.l1_accept
                    l2_acc = q2_state in l2_dfa_accept
                    if l1_acc != l2_acc:
                        if (q1_state, q2_state) not in symdiff_visited:
                            symdiff_visited.add((q1_state, q2_state))
                            if first_witness is None:
                                first_witness = w

                    # Expand transitions
                    for a in symbols:
                        next_q1 = self.l1_transitions.get((q1_state, a))
                        next_q2 = l2_dfa_trans.get((q2_state, a))
                        if next_q1 is None or next_q2 is None:
                            continue
                        nxt = (next_q1, next_q2)
                        if nxt not in visited:
                            visited.add(nxt)
                            queue.append((nxt, w + a))

                return total_product_states, len(symdiff_visited), (first_witness or '')

            def test_equivalence(self):
                # Step 1: NFA -> DFA
                l2_count, l2_dfa_trans, l2_dfa_accept, l2_dfa_states = self.convert_nfa_to_dfa()

                # Step 2 & 3: Product size and reachable symmetric-difference via BFS
                prod_states, reachable_diff, witness = self.analyze_product_and_symdiff(
                    l2_dfa_trans, l2_dfa_accept, l2_dfa_states
                )

                # Step 4: Equivalence
                equivalent = 'EQUIVALENT' if reachable_diff == 0 else 'NOT_EQUIVALENT'

                return (l2_count, prod_states, reachable_diff, equivalent, witness)

        tester = EquivalenceTester()
        result = tester.test_equivalence()
        return (nfa_dfa_states == result[0] and
                product_states == result[1] and
                symmetric_diff_states == result[2] and
                equivalence_result == result[3] and
                witness_string == result[4])
    except Exception:
        return False

