        R0, R1, R2, R3, N, M = answer

        # ===== Regex AST definitions =====
        class Empty:  # ∅
            def __repr__(self):
                return '∅'

        class Eps:  # ε
            def __repr__(self):
                return 'ε'

        class Sym:
            def __init__(self, ch):
                self.ch = ch
            def __repr__(self):
                return self.ch

        class Union:
            def __init__(self, left, right):
                self.left = left
                self.right = right
            def __repr__(self):
                return f'({self.left}|{self.right})'

        class Concat:
            def __init__(self, left, right):
                self.left = left
                self.right = right
            def __repr__(self):
                return f'({self.left}{self.right})'

        class Star:
            def __init__(self, node):
                self.node = node
            def __repr__(self):
                return f'({self.node})*'

        class Plus:
            def __init__(self, node):
                self.node = node
            def __repr__(self):
                return f'({self.node})+'

        # ===== Parser (supporting |, concatenation, *, +) =====
        class Parser:
            def __init__(self, s):
                self.s = s
                self.i = 0
            def peek(self):
                return self.s[self.i] if self.i < len(self.s) else None
            def eat(self, ch=None):
                c = self.peek()
                if ch is None or c == ch:
                    self.i += 1
                    return c
                raise ValueError('parse error')
            def parse(self):
                node = self.parse_expr()
                if self.peek() is not None:
                    raise ValueError('unexpected input')
                return node
            def parse_expr(self):
                node = self.parse_term()
                while self.peek() == '|':
                    self.eat('|')
                    node = Union(node, self.parse_term())
                return node
            def parse_term(self):
                factors = []
                while True:
                    c = self.peek()
                    if c is None or c in ')|':
                        break
                    factors.append(self.parse_factor())
                if not factors:
                    return Eps()  # empty concatenation as ε
                node = factors[0]
                for f in factors[1:]:
                    node = Concat(node, f)
                return node
            def parse_factor(self):
                node = self.parse_base()
                while True:
                    c = self.peek()
                    if c == '*':
                        self.eat('*')
                        node = Star(node)
                    elif c == '+':
                        self.eat('+')
                        node = Plus(node)
                    else:
                        break
                return node
            def parse_base(self):
                c = self.peek()
                if c in ('a', 'b'):
                    self.eat()
                    return Sym(c)
                if c == 'ε':
                    self.eat()
                    return Eps()
                if c == '∅':
                    self.eat()
                    return Empty()
                if c == '(':
                    self.eat('(')
                    node = self.parse_expr()
                    self.eat(')')
                    return node
                raise ValueError('unexpected base')

        # ===== Normalization/printing =====
        def is_empty(n):
            return isinstance(n, Empty)
        def is_eps(n):
            return isinstance(n, Eps)
        def is_sym(n, ch=None):
            return isinstance(n, Sym) and (ch is None or n.ch == ch)

        def simplify(node):
            # Recursive simplify
            if isinstance(node, Union):
                l = simplify(node.left)
                r = simplify(node.right)
                if is_empty(l):
                    return r
                if is_empty(r):
                    return l
                if repr(l) == repr(r):
                    return l
                return Union(l, r)
            if isinstance(node, Concat):
                l = simplify(node.left)
                r = simplify(node.right)
                if is_empty(l) or is_empty(r):
                    return Empty()
                if is_eps(l):
                    return r
                if is_eps(r):
                    return l
                return Concat(l, r)
            if isinstance(node, Star):
                inner = simplify(node.node)
                if is_empty(inner) or is_eps(inner):
                    return Eps()
                return Star(inner)
            if isinstance(node, Plus):
                inner = simplify(node.node)
                if is_empty(inner):
                    return Empty()
                if is_eps(inner):
                    return Eps()
                return Plus(inner)
            return node

        def precedence(n):
            if isinstance(n, Union):
                return 1
            if isinstance(n, Concat):
                return 2
            if isinstance(n, (Star, Plus)):
                return 3
            return 4  # Sym, Eps, Empty

        def to_string(node, parent_prec=0):
            # canonical textual form
            if isinstance(node, Empty):
                return '∅'
            if isinstance(node, Eps):
                return 'ε'
            if isinstance(node, Sym):
                return node.ch
            if isinstance(node, Star):
                child = node.node
                s = to_string(child, 3)
                if precedence(child) < 3:
                    s = f'({s})'
                return s + '*'
            if isinstance(node, Plus):
                child = node.node
                s = to_string(child, 3)
                if precedence(child) < 3:
                    s = f'({s})'
                return s + '+'
            if isinstance(node, Concat):
                l, r = node.left, node.right
                ls = to_string(l, 2)
                rs = to_string(r, 2)
                if precedence(l) < 2:
                    ls = f'({ls})'
                if precedence(r) < 2:
                    rs = f'({rs})'
                return ls + rs
            if isinstance(node, Union):
                l, r = node.left, node.right
                ls = to_string(l, 1)
                rs = to_string(r, 1)
                return ls + '|' + rs
            return repr(node)

        # ===== Derivative and nullability =====
        def is_nullable(node):
            if isinstance(node, Eps):
                return True
            if isinstance(node, Empty):
                return False
            if isinstance(node, Sym):
                return False
            if isinstance(node, Star):
                return True
            if isinstance(node, Plus):
                return is_nullable(node.node)
            if isinstance(node, Concat):
                return is_nullable(node.left) and is_nullable(node.right)
            if isinstance(node, Union):
                return is_nullable(node.left) or is_nullable(node.right)
            return False

        def D(node, a):
            if isinstance(node, Empty):
                return Empty()
            if isinstance(node, Eps):
                return Empty()
            if isinstance(node, Sym):
                return Eps() if node.ch == a else Empty()
            if isinstance(node, Union):
                return simplify(Union(D(node.left, a), D(node.right, a)))
            if isinstance(node, Concat):
                first = Concat(D(node.left, a), node.right)
                second = D(node.right, a) if is_nullable(node.left) else Empty()
                return simplify(Union(first, second))
            if isinstance(node, Star):
                return simplify(Concat(D(node.node, a), Star(node.node)))
            if isinstance(node, Plus):
                return simplify(Concat(D(node.node, a), Star(node.node)))
            return Empty()

        def compute_derivatives_str(regex_str, s):
            root = simplify(Parser(regex_str).parse())
            current = root
            parts = [to_string(current)]
            for ch in s:
                current = simplify(D(current, ch))
                parts.append(to_string(current))
            return parts, is_nullable(current)

