                return False

            def refine_partition(self, current_partitions):
                """Refine partitions based on distinguishability"""
                new_partitions = []
                refinement_occurred = False

                for partition in current_partitions:
                    if len(partition) <= 1:
                        new_partitions.append(partition)
                        continue

                    # Group states that are indistinguishable
                    groups = []
                    remaining_states = list(partition)

                    while remaining_states:
                        current_state = remaining_states.pop(0)
                        current_group = [current_state]

                        # Find all states indistinguishable from current_state
                        to_remove = []
                        for other_state in remaining_states:
                            if not self.can_distinguish(current_state, other_state, current_partitions):
                                current_group.append(other_state)
                                to_remove.append(other_state)

                        # Remove states that joined current group
                        for state in to_remove:
                            remaining_states.remove(state)

                        groups.append(tuple(sorted(current_group)))

                    # If partition was split, refinement occurred
                    if len(groups) > 1:
                        refinement_occurred = True

                    new_partitions.extend(groups)

                return tuple(sorted(new_partitions, key=lambda x: min(x))), refinement_occurred

            def hopcroft_minimize(self):
                """Perform Hopcroft minimization algorithm"""
                # Start with initial partition
                current_partitions = self.initial_partition()
                initial_part = current_partitions

                iteration_count = 0
                refinement_count = 0
                max_iterations = 10

                while iteration_count < max_iterations:
                    new_partitions, refined = self.refine_partition(current_partitions)
                    iteration_count += 1

                    if refined:
                        refinement_count += 1

                    if new_partitions == current_partitions:
                        break

                    current_partitions = new_partitions

                return {
                    'initial_partition': initial_part,
                    'iterations': iteration_count,
                    'refinements': refinement_count,
                    'final_equivalence_classes': len(current_partitions),
                    'minimized_states': len(current_partitions)
                }

        minimizer = HopcroftMinimizer()
        result = minimizer.hopcroft_minimize()

        # Compare partitions (order-independent)
        def partitions_match(p1, p2):
            return set(frozenset(group) for group in p1) == set(frozenset(group) for group in p2)

        return (partitions_match(initial_partition, result['initial_partition']) and
                iterations == result['iterations'] and
                refinements == result['refinements'] and
                final_classes == result['final_equivalence_classes'] and
                min_states == result['minimized_states'])
    except Exception as e:
        print(e)
        return False

