        class UltimateRegularSimulator:
            def __init__(self):
                self.test_string = "012210"
                self.target_pattern = "012"

            def construct_pattern_dfa(self):
                """DFA for strings containing \"012\""""
                # States: q0 (start), q1 (seen 0), q2 (seen 01), q3 (seen 012, accept)
                states = {'q0', 'q1', 'q2', 'q3'}
                transitions = {
                    ('q0', '0'): 'q1', ('q0', '1'): 'q0', ('q0', '2'): 'q0',
                    ('q1', '0'): 'q1', ('q1', '1'): 'q2', ('q1', '2'): 'q0',
                    ('q2', '0'): 'q1', ('q2', '1'): 'q0', ('q2', '2'): 'q3',
                    ('q3', '0'): 'q3', ('q3', '1'): 'q3', ('q3', '2'): 'q3'
                }
                accept = {'q3'}
                return len(states), transitions, accept

            def construct_parity_dfa(self):
                """DFA for even length strings"""
                # States: even, odd
                states = {'even', 'odd'}
                transitions = {
                    ('even', '0'): 'odd', ('even', '1'): 'odd', ('even', '2'): 'odd',
                    ('odd', '0'): 'even', ('odd', '1'): 'even', ('odd', '2'): 'even'
                }
                accept = {'even'}
                return len(states), transitions, accept

            def construct_modular_dfa(self):
                """DFA for digit sum ≡ 0 (mod 3)"""
                # States: mod0, mod1, mod2
                states = {'mod0', 'mod1', 'mod2'}
                transitions = {
                    ('mod0', '0'): 'mod0', ('mod0', '1'): 'mod1', ('mod0', '2'): 'mod2',
                    ('mod1', '0'): 'mod1', ('mod1', '1'): 'mod2', ('mod1', '2'): 'mod0',
                    ('mod2', '0'): 'mod2', ('mod2', '1'): 'mod0', ('mod2', '2'): 'mod1'
                }
                accept = {'mod0'}
                return len(states), transitions, accept

            def construct_product_automaton(self):
                """Construct product of all three DFAs"""
                pattern_count, pattern_trans, pattern_accept = self.construct_pattern_dfa()
                parity_count, parity_trans, parity_accept = self.construct_parity_dfa()
                mod_count, mod_trans, mod_accept = self.construct_modular_dfa()

                # Product state space
                pattern_states = {'q0', 'q1', 'q2', 'q3'}
                parity_states = {'even', 'odd'}
                mod_states = {'mod0', 'mod1', 'mod2'}

                product_states = []
                for p in pattern_states:
                    for par in parity_states:
                        for m in mod_states:
                            product_states.append((p, par, m))

                # Product transitions
                product_transitions = {}
                for state in product_states:
                    p, par, m = state
                    for symbol in ['0', '1', '2']:
                        if ((p, symbol) in pattern_trans and 
                            (par, symbol) in parity_trans and 
                            (m, symbol) in mod_trans):
                            next_p = pattern_trans[(p, symbol)]
                            next_par = parity_trans[(par, symbol)]
                            next_m = mod_trans[(m, symbol)]
                            product_transitions[(state, symbol)] = (next_p, next_par, next_m)

                # Product accepting states
                product_accept = []
                for state in product_states:
                    p, par, m = state
                    if p in pattern_accept and par in parity_accept and m in mod_accept:
                        product_accept.append(state)

                return {
                    'states': len(product_states),
                    'transitions': product_transitions,
                    'accept': product_accept,
                    'start': ('q0', 'even', 'mod0')
                }

            def simulate_individual_constraints(self, string):
                """Test each constraint individually"""
                # Pattern constraint
                pattern_found = self.target_pattern in string

                # Parity constraint
                even_length = len(string) % 2 == 0

                # Modular constraint
                digit_sum = sum(int(digit) for digit in string)
                mod_constraint = digit_sum % 3 == 0

                return pattern_found, even_length, mod_constraint

            def simulate_product_automaton(self, product_auto, string):
                """Simulate string on product automaton"""
                current_state = product_auto['start']

                for symbol in string:
                    if (current_state, symbol) in product_auto['transitions']:
                        current_state = product_auto['transitions'][(current_state, symbol)]
                    else:
                        return False

                return current_state in product_auto['accept']

            def estimate_optimization(self, product_auto):
                """Estimate optimization potential through minimization"""
                # Theoretical optimization: many states may be equivalent
                # Estimate 25% reduction through minimization
                original_states = product_auto['states']
                optimized_estimate = int(original_states * 0.75)
                return optimized_estimate

            def full_simulation(self):
                """Perform complete simulation and analysis"""
                # Construct individual DFAs
                pattern_count, _, _ = self.construct_pattern_dfa()
                parity_count, _, _ = self.construct_parity_dfa()
                mod_count, _, _ = self.construct_modular_dfa()

                # Construct product automaton
                product_auto = self.construct_product_automaton()

                # Test individual constraints
                pattern_ok, parity_ok, mod_ok = self.simulate_individual_constraints(self.test_string)

                # Test product automaton
                product_accepts = self.simulate_product_automaton(product_auto, self.test_string)

                # Estimate optimization
                optimized_count = self.estimate_optimization(product_auto)

                return {
                    'pattern_states': pattern_count,
                    'parity_states': parity_count,
                    'mod_states': mod_count,
                    'total_states': product_auto['states'],
                    'individual_analysis': (pattern_ok, parity_ok, mod_ok, product_accepts),
                    'optimized_states': optimized_count
                }

        simulator = UltimateRegularSimulator()
        result = simulator.full_simulation()

        return (pattern_states == result['pattern_states'] and
                parity_states == result['parity_states'] and
                mod_states == result['mod_states'] and
                total_states == result['total_states'] and
                analysis_result == result['individual_analysis'] and
                optimized_states == result['optimized_states'])
    except:
        return False

